import{_ as e,o as r,c as o,ae as d}from"./chunks/framework.B6gjLfeO.js";const u=JSON.parse('{"title":"mParticle (Import) Configuration","description":"","frontmatter":{"title":"mParticle (Import) Configuration","slug":"mparticle-import-configuration"},"headers":[],"relativePath":"developer-hub/mparticle-import-configuration.md","filePath":"developer-hub/mparticle-import-configuration.md"}'),n={name:"developer-hub/mparticle-import-configuration.md"};function a(i,t,c,s,h,l){return r(),o("div",null,[...t[0]||(t[0]=[d('<p><em>[Image: 1328]</em></p><h2 id="overview" tabindex="-1">Overview <a class="header-anchor" href="#overview" aria-label="Permalink to &quot;Overview&quot;">​</a></h2><p>Sending events from mParticle to Branch will allow you to attribute downstream conversions like purchases across web and app to Branch link clicks. Events imported from mParticle to Branch will be available wherever you can normally use events within Branch, including dashboard visualizations, Data Feeds, Ads Postbacks, Journeys targeting, Liveview and more.</p><p>This guide walks through the server-side integration for data import from mParticle to Branch. For the client-side integration, see the <a href="./mparticle-ios.html">mParticle iOS</a> or <a href="./mparticle-android.html">android</a> documentation. For data export from Branch to mParticle, go <a href="./mparticle-export.html">here</a>.</p><h2 id="how-does-it-work" tabindex="-1">How does it work? <a class="header-anchor" href="#how-does-it-work" aria-label="Permalink to &quot;How does it work?&quot;">​</a></h2><p>Once the Branch SDK is integrated into an app, Branch can detect which Branch Links are leading to installs, re-opens, and users&#39; actions. Enabling this integration and sending your events to Branch will allow Branch to enhance your mParticle data with Branch data.</p><h3 id="branch-events-imported-from-mparticle" tabindex="-1">Branch Events Imported from mParticle <a class="header-anchor" href="#branch-events-imported-from-mparticle" aria-label="Permalink to &quot;Branch Events Imported from mParticle&quot;">​</a></h3><p>Branch will import events that are not auto-tracked with the Branch SDKs. This includes commerce, content, user lifecycle, and custom events, and excludes events like clicks and installs. See the full list of supported events and associated mappings <a href="./mparticle-import.html#section-supported-events">here</a>. Branch will only import events that can be <a href="./mparticle-import.html#identifiers">tied to a user</a>.</p><div class="warning custom-block"><p class="custom-block-title">Avoid Duplicate Data</p><p>To avoid duplicate data, you should either <a href="./track-branch-events.html">track conversion events directly with Branch</a> or track events with mParticle and then enable import to Branch, not both. Branch will warn you if you try to import events to Branch that you are already tracking.</p></div><p>The Branch integration supports some of the events tracked with mParticle’s <a href="https://docs.mparticle.com/developers/server/json-reference/#events" target="_blank" rel="noreferrer">API or SDKs</a>. Branch will only import events from mParticle that are not already auto-tracked with the Branch SDK. This means that events like click and install cannot be imported. The following outlines how mParticle events are mapped to Branch events, and which will be imported to Branch:</p><table tabindex="0"><thead><tr><th>mParticle Action</th><th>mParticle Event Type</th><th>mParticle Custom Event Type</th><th>Branch Event</th><th>Branch Event Category</th><th>Imported</th></tr></thead><tbody><tr><td><code>add_to_cart</code></td><td><code>product_action</code></td><td>-</td><td>Add To Cart</td><td>Commerce Event</td><td><strong>Yes</strong></td></tr><tr><td><code>add_to_wishlist</code></td><td><code>product_action</code></td><td>-</td><td>Add To Wishlist</td><td>Commerce Event</td><td><strong>Yes</strong></td></tr><tr><td><em>use the Branch event name</em></td><td>-</td><td>-</td><td>View Cart</td><td>Commerce Event</td><td><strong>Yes</strong></td></tr><tr><td><em>use the Branch event name</em></td><td>-</td><td>-</td><td>Add Payment Info</td><td>Commerce Event</td><td><strong>Yes</strong></td></tr><tr><td><code>checkout</code></td><td><code>product_action</code></td><td>-</td><td>Initiate Purchase</td><td>Commerce Event</td><td><strong>Yes</strong></td></tr><tr><td><code>purchase</code></td><td><code>product_action</code></td><td>-</td><td>Purchase</td><td>Commerce Event</td><td><strong>Yes</strong></td></tr><tr><td><em>use the Branch event name</em></td><td>-</td><td>-</td><td>Spend Credits</td><td>Commerce Event</td><td><strong>Yes</strong></td></tr><tr><td><em>use the Branch event name</em></td><td><code>custom_event</code></td><td><code>search</code></td><td>Search</td><td>Content Event</td><td><strong>Yes</strong></td></tr><tr><td><code>view_detail</code></td><td><code>product_action</code></td><td>-</td><td>View Item</td><td>Content Event</td><td><strong>Yes</strong></td></tr><tr><td><em>use the Branch event name</em></td><td>-</td><td>-</td><td>Rate</td><td>Content Event</td><td><strong>Yes</strong></td></tr><tr><td><em>use the Branch event name</em></td><td>-</td><td>-</td><td>Share</td><td>Content Event</td><td><strong>Yes</strong></td></tr><tr><td><em>use the Branch event name</em></td><td>-</td><td>-</td><td>Complete Registration</td><td>Lifecycle Event</td><td><strong>Yes</strong></td></tr><tr><td><em>use the Branch event name</em></td><td>-</td><td>-</td><td>Complete Tutorial</td><td>Lifecycle Event</td><td><strong>Yes</strong></td></tr><tr><td><em>use the Branch event name</em></td><td>-</td><td>-</td><td>Achieve Level</td><td>Lifecycle Event</td><td><strong>Yes</strong></td></tr><tr><td><em>use the Branch event name</em></td><td>-</td><td>-</td><td>Unlock Achievement</td><td>Lifecycle Event</td><td><strong>Yes</strong></td></tr><tr><td><em>use the Branch event name</em></td><td>-</td><td>-</td><td>Custom</td><td>Custom Event</td><td><strong>Yes</strong></td></tr><tr><td>-</td><td>-</td><td>-</td><td>Click</td><td>-</td><td>No</td></tr><tr><td>-</td><td>-</td><td>-</td><td>Install</td><td>-</td><td>No</td></tr><tr><td>-</td><td>-</td><td>-</td><td>Reinstall</td><td>-</td><td>No</td></tr><tr><td>-</td><td>-</td><td>-</td><td>Open</td><td>-</td><td>No</td></tr><tr><td>-</td><td>-</td><td>-</td><td>SMS Sent</td><td>-</td><td>No</td></tr><tr><td>-</td><td>-</td><td>-</td><td>Pageview</td><td>-</td><td>No</td></tr><tr><td>-</td><td>-</td><td>-</td><td>Web Session Start</td><td>-</td><td>No</td></tr><tr><td>-</td><td>-</td><td>-</td><td>Branch CTA View</td><td>-</td><td>No</td></tr><tr><td>-</td><td>-</td><td>-</td><td>Impression</td><td>-</td><td>No</td></tr></tbody></table><h2 id="prerequisites" tabindex="-1">Prerequisites <a class="header-anchor" href="#prerequisites" aria-label="Permalink to &quot;Prerequisites&quot;">​</a></h2><p>In order to enable mParticle (import), you need to have completed the following:</p><ol><li>Admin access to your <a href="https://dashboard.branch.io/" target="_blank" rel="noreferrer">Branch Dashboard</a>.</li><li>Have either the Engagement or Performance <a href="./packaging.html">product</a> enabled for your Branch Account.</li><li>Implemented the Branch SDK into your mobile app (<a href="./ios-sdk-overview.html">iOS</a> | <a href="./android-sdk-overview.html">Android</a>)</li><li>Implement the mParticle SDK</li><li>Admin access to your mParticle account.</li></ol><h2 id="enable-mparticle-import" tabindex="-1">Enable mParticle (import) <a class="header-anchor" href="#enable-mparticle-import" aria-label="Permalink to &quot;Enable mParticle (import)&quot;">​</a></h2><h2 id="_1-setup-branch" tabindex="-1">1. Setup Branch <a class="header-anchor" href="#_1-setup-branch" aria-label="Permalink to &quot;1. Setup Branch&quot;">​</a></h2><p><a href="./submit-a-ticket.html">Contact Branch</a> to configure Branch to receive events from mParticle. Please note that a subscription to <a href="https://branch.io/data-feeds/" target="_blank" rel="noreferrer">Data Feeds</a> is required to enable data import from mParticle to Branch.</p><p>Then, navigate to the <a href="https://branch.dashboard.branch.io/data-feeds/integrations" target="_blank" rel="noreferrer">Data Integrations page</a> of the Branch dashboard.</p><ol><li>Select <strong>mParticle</strong> from the menu on the left.</li><li>Select the platforms you would like to import events from and click <strong>Save</strong>.</li></ol><h2 id="_2-setup-mparticle" tabindex="-1">2. Setup mParticle <a class="header-anchor" href="#_2-setup-mparticle" aria-label="Permalink to &quot;2. Setup mParticle&quot;">​</a></h2><p>Navigate to your your mParticle UI’s Connections page.</p><ol><li>Select an input and add Branch S2S as the output.</li><li>Enter your Branch Key. This can be found in the <a href="https://dashboard.branch.io/account-settings/app" target="_blank" rel="noreferrer">Account Settings &gt; App</a> section of the Branch dashboard.</li><li>Enter your Branch Secret. This can be found in the <a href="https://dashboard.branch.io/account-settings/app" target="_blank" rel="noreferrer">Account Settings &gt; App</a> section of the Branch dashboard.</li></ol><h4 id="identifiers" tabindex="-1">Identifiers <a class="header-anchor" href="#identifiers" aria-label="Permalink to &quot;Identifiers&quot;">​</a></h4><p>Identifiers are required for events to be imported to Branch. You must include:</p><ul><li><code>context.userId.Customer</code> <strong>or</strong> <code>context.userId.mpid</code> <strong>or</strong> <code>context.userId.other</code> <strong>or</strong> <code>context.userId.other&lt;2-10&gt;</code></li><li>(<code>environment.Identity.DeviceIdentity.IOS_ADVERTISING_ID</code> <strong>or</strong> <code>environment.Identity.DeviceIdentity.IOS_VENDOR_ID</code>) <strong>and</strong> <code>context.runtimeEnvironment.type</code> <strong>or</strong></li><li>(<code>environment.Identity.DeviceIdentity.GOOGLE_ADVERTISING_ID</code> <strong>or</strong> <code>environment.Identity.DeviceIdentity.ANDROID_ID</code>) <strong>and</strong> <code>context.runtimeEnvironment.type</code></li></ul><p>Branch maps mParticle&#39;s identifiers to the following:</p><table tabindex="0"><thead><tr><th>mParticle field</th><th>Branch field</th></tr></thead><tbody><tr><td><code>context.userId.Customer</code> <code>context.userId.mpid</code> <code>context.userId.other</code> <code>context.userId.other2</code> <code>context.userId.other3</code> <code>context.userId.other4</code> <code>context.userId.other5</code> <code>context.userId.other6</code> <code>context.userId.other7</code> <code>context.userId.other8</code> <code>context.userId.other9</code> <code>context.userId.other10</code></td><td><code>developer_identity</code></td></tr><tr><td><code>environment.Identity.DeviceIdentity.IOS_ADVERTISING_ID</code></td><td><code>idfa</code></td></tr><tr><td><code>environment.Identity.DeviceIdentity.GOOGLE_ADVERTISING_ID</code></td><td><code>aaid</code></td></tr><tr><td><code>environment.Identity.DeviceIdentity.IOS_VENDOR_ID</code></td><td><code>idfv</code></td></tr><tr><td><code>environment.Identity.DeviceIdentity.ANDROID_ID</code></td><td><code>android_id</code></td></tr><tr><td><code>context.runtimeEnvironment.type</code></td><td><code>os</code></td></tr></tbody></table><p>At this time, Branch <a href="./mparticle-import.html#attribution-for-logged-out-users-on-web">will not attribute logged out web events</a> received from the server-to-server integration.</p><h2 id="_3-verify-the-integration" tabindex="-1">3. Verify the integration <a class="header-anchor" href="#_3-verify-the-integration" aria-label="Permalink to &quot;3. Verify the integration&quot;">​</a></h2><p>Once you have import turned on in both mParticle and Branch, events should come through. You will see a green dot on the import card if Branch has seen events:</p><p>.png &quot;09a44fd-mparticle-import-status.png&quot;)</p><p>Branch imports events from mParticle as <a href="./mparticle-import.html#section-supported-events">commerce, user lifecycle, content, or custom events</a>. To see more information on the events that are coming in, you can look at events with <strong>origin</strong> <code>MPARTICLE</code> in <a href="https://dashboard.branch.io/liveview/events" target="_blank" rel="noreferrer">Liveview</a>.</p><h4 id="using-imported-events" tabindex="-1">Using imported events <a class="header-anchor" href="#using-imported-events" aria-label="Permalink to &quot;Using imported events&quot;">​</a></h4><p>Events imported from mParticle to Branch will be available wherever you can normally use events within Branch. This includes dashboard visualizations, Data Feeds (including Data Integrations, Query API, Webhooks, and Daily Export API), Ads postbacks, Journeys targeting, Liveview and more.</p><h2 id="advanced" tabindex="-1">Advanced <a class="header-anchor" href="#advanced" aria-label="Permalink to &quot;Advanced&quot;">​</a></h2><h3 id="attribution-for-logged-out-users-on-web" tabindex="-1">Attribution for logged out users on web <a class="header-anchor" href="#attribution-for-logged-out-users-on-web" aria-label="Permalink to &quot;Attribution for logged out users on web&quot;">​</a></h3><p>Branch uses a custom, in-house identifier for logged out users on web. If you enable the server to server integration from mParticle to Branch, you will not be able to attribute logged out web events to a campaign run with Branch. For this reason, you may want to track web events directly with the Branch web SDK, while still sending app events server to server from mParticle. Branch allows you to then toggle web event import off to prevent duplicate data.</p><h3 id="enabling-roku-ott-events" tabindex="-1">Enabling Roku OTT Events <a class="header-anchor" href="#enabling-roku-ott-events" aria-label="Permalink to &quot;Enabling Roku OTT Events&quot;">​</a></h3><div class="warning custom-block"><p class="custom-block-title">Prerequisite</p><p>You must complete the above set up steps<br> You must have <strong>OTHER</strong> events checked in the <a href="https://branch.dashboard.branch.io/data-feeds/integrations" target="_blank" rel="noreferrer">Branch Dashboard mParticle Integration</a></p></div><div class="info custom-block"><p class="custom-block-title">Events Supported</p><p>OTT mParticle import will not give Branch OPEN events. (OPEN events coming soon)<br> Branch imports session_start events as a custom event.</p></div><p>Enabling the Connection in the mParticle Dashboard:</p><ol><li><p>Once the Branch S2S module has been configured, it can be selected as a destination via the mParticle connections UI (screenshot below).</p></li><li><p>Select the Roku platform input and connect it to Branch without any transformations applied.</p></li><li><p>Enter your <a href="https://branch.dashboard.branch.io/account-settings/profile" target="_blank" rel="noreferrer">Branch Key and Branch Secret</a> in order to configure the Branch S2S integration.</p></li></ol>',42)])])}const p=e(n,[["render",a]]);export{u as __pageData,p as default};
